/* ================================================================
   Chairman Message — Final  (uses theme.css variables)
   ================================================================ */

.chairman-section {
  padding: 140px 0 120px;
  background: var(--bg-secondary);
  position: relative;
  overflow: hidden;
  border-top: 1px solid var(--border-light);
  transition: background 0.4s ease;
}

/* ── Ambient orbs ──────────────────────────────────────────── */
.chairman-orb {
  position: absolute;
  border-radius: 50%;
  pointer-events: none;
  filter: blur(120px);
}

.chairman-orb--1 {
  width: 600px;
  height: 600px;
  background: var(--orb-1);
  top: -200px;
  left: -180px;
}

.chairman-orb--2 {
  width: 500px;
  height: 500px;
  background: var(--orb-2);
  bottom: -150px;
  right: -120px;
}

/* ── Grid ──────────────────────────────────────────────────── */
.chairman-grid {
  display: grid;
  grid-template-columns: 1fr 1.1fr;
  gap: 80px;
  align-items: center;
  position: relative;
  z-index: 2;
}

/* ── Image Column ──────────────────────────────────────────── */
.chairman-img-col {
  display: flex;
  flex-direction: column;
  gap: 28px;
}

.img-frame {
  position: relative;
}

.img-glow {
  position: absolute;
  inset: -24px;
  background: radial-gradient(circle at 50% 50%, var(--accent-glow), transparent 70%);
  filter: blur(30px);
  z-index: 0;
  pointer-events: none;
}

.img-mask {
  position: relative;
  z-index: 1;
  overflow: hidden;
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-lg);
  max-height: 680px;
}

.img-mask::after {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(to top, rgba(0, 0, 0, 0.55) 0%, transparent 50%);
  pointer-events: none;
  z-index: 2;
}

.chairman-img {
  width: 100%;
  height: auto;
  display: block;
  object-fit: cover;
  transition: filter 0.8s ease, transform 0.8s ease;
  transform-origin: center bottom;
}

.img-mask:hover .chairman-img {
  filter: grayscale(0%) contrast(1.05);
  transform: scale(1.04);
}

/* Chairman badge overlay */
.chairman-badge {
  position: absolute;
  bottom: 24px;
  left: 24px;
  z-index: 4;
  background: var(--bg-glass);
  backdrop-filter: blur(16px);
  border: 1px solid var(--border-gold);
  border-radius: var(--radius-md);
  padding: 14px 20px;
}

.badge-name {
  display: block;
  font-family: var(--font-secondary);
  font-size: 18px;
  color: var(--text-primary);
  font-weight: 700;
}

.badge-role {
  display: block;
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 2px;
  color: var(--accent-primary);
  margin-top: 3px;
}

/* Stats strip */
.chairman-stats {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 24px 28px;
  background: var(--bg-card);
  border: 1px solid var(--border-light);
  border-radius: var(--radius-lg);
  backdrop-filter: blur(12px);
}

.cstat {
  text-align: center;
  flex: 1;
}

.cstat strong {
  display: block;
  font-family: var(--font-secondary);
  font-size: 30px;
  font-weight: 700;
  color: var(--accent-primary);
  line-height: 1;
  margin-bottom: 6px;
}

.cstat span {
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 1.5px;
  color: var(--text-muted);
}

.cstat-divider {
  width: 1px;
  height: 40px;
  background: var(--border-light);
  flex-shrink: 0;
}

/* ── Text Column ───────────────────────────────────────────── */
.chairman-text-col {
  display: flex;
  flex-direction: column;
  gap: 0;
  position: relative;
  z-index: 2;
}

.chairman-quote-block {
  position: relative;
  margin: 16px 0 36px;
}

.chairman-quote-mark {
  font-family: var(--font-display);
  font-size: 120px;
  line-height: 0.7;
  color: var(--accent-primary);
  opacity: 0.15;
  display: block;
  margin-bottom: -30px;
  user-select: none;
}

.chairman-heading {
  font-family: var(--font-secondary);
  font-size: clamp(2rem, 4vw, 3.6rem);
  line-height: 1.12;
  color: var(--text-primary);
  margin: 0;
}

.text-body {
  display: flex;
  flex-direction: column;
  gap: 20px;
  margin-bottom: 44px;
}

.text-body p {
  font-size: 16.5px;
  line-height: 1.85;
  color: var(--text-secondary);
  font-weight: 300;
}

/* Signature */
.sign-off {
  display: flex;
  align-items: center;
  gap: 24px;
  margin-bottom: 40px;
}

.sign-line {
  width: 3px;
  height: 56px;
  background: var(--accent-gradient);
  border-radius: 2px;
  flex-shrink: 0;
}

.sign-text {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.sign-name {
  font-family: var(--font-secondary);
  font-size: 22px;
  font-weight: 700;
  color: var(--text-primary);
}

.sign-title {
  font-size: 12px;
  text-transform: uppercase;
  letter-spacing: 2px;
  color: var(--text-muted);
}

/* Pills */
.chairman-pills {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
}

.chairman-pill {
  padding: 7px 16px;
  border: 1px solid var(--border-gold);
  border-radius: 30px;
  font-size: 12px;
  font-weight: 500;
  letter-spacing: 0.5px;
  color: var(--accent-primary);
  background: var(--accent-light);
  transition: var(--transition-fast);
  cursor: default;
}

.chairman-pill:hover {
  background: var(--accent-primary);
  color: var(--text-invert);
  border-color: var(--accent-primary);
}

/* ── Responsive ────────────────────────────────────────────── */
@media (max-width: 1024px) {
  .chairman-grid {
    grid-template-columns: 1fr;
    gap: 56px;
  }

  .img-mask {
    max-height: 500px;
  }
}

@media (max-width: 600px) {
  .chairman-section {
    padding: 90px 0 80px;
  }

  .chairman-heading {
    font-size: 2.2rem;
  }

  .chairman-stats {
    padding: 18px 16px;
    gap: 8px;
  }

  .cstat strong {
    font-size: 24px;
  }

  .sign-off {
    flex-direction: column;
    align-items: flex-start;
  }

  .sign-line {
    width: 40px;
    height: 3px;
  }
}
